Write-Host "=== BudgetNew Premium Setup ===" -ForegroundColor Cyan

Write-Host "[1/5] Clonage budget1..." -ForegroundColor Yellow
$gitOut = git clone https://github.com/mamadouelimanewane/budget1.git _tmp_base 2>&1
if (-not (Test-Path "_tmp_base")) { Write-Host "ERREUR: clone budget1 echoue" -ForegroundColor Red; exit 1 }
Write-Host "  OK" -ForegroundColor Gray

Write-Host "[2/5] Copie des fichiers de base..." -ForegroundColor Yellow
Copy-Item "_tmp_base\backend" -Destination "." -Recurse -Force
Copy-Item "_tmp_base\frontend" -Destination "." -Recurse -Force
if (Test-Path "_tmp_base\docker-compose.yml") { Copy-Item "_tmp_base\docker-compose.yml" "." -Force }
if (Test-Path "_tmp_base\.gitignore") { Copy-Item "_tmp_base\.gitignore" "." -Force }
Remove-Item "_tmp_base" -Recurse -Force
Write-Host "  OK" -ForegroundColor Gray

Write-Host "[3/5] Ecriture des fichiers Premium..." -ForegroundColor Yellow

function Write-B64 { param($p,$b) 
  $full = Join-Path (Get-Location).Path $p
  $dir = Split-Path $full -Parent
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [Convert]::FromBase64String($b)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($full, $text, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  -> $p" -ForegroundColor Gray
}

Write-B64 "backend\app\models_premium.py" ""
